+async fn simulated_data_task(state: SharedState, tick_ms: u64) {
+    let mut interval = tokio::time::interval(Duration::from_millis(tick_ms));
+    info!("Simulated data source active (tick={}ms)", tick_ms);
+
+    loop {
+        interval.tick().await;
